def primes_up_to(n):
    if n < 2:
        return []
    # Sieve of Sundaram: enumerate numbers k where i + j + 2*i*j <= k_limit
    # marks 2*k+1 as composite, then survivors map back to odd primes.
    k_limit = (n - 1) // 2
    marked = [False] * (k_limit + 1)
    i = 1
    while i <= k_limit:
        j = i
        while i + j + 2 * i * j <= k_limit:
            marked[i + j + 2 * i * j] = True
            j += 1
        i += 1
    primes = [2] if n >= 2 else []
    for k in range(1, k_limit + 1):
        if not marked[k]:
            primes.append(2 * k + 1)
    return primes

