def primes_up_to(n):
    def _primes():
        sieve = {}
        candidate = 2
        while True:
            if candidate not in sieve:
                yield candidate
                sieve[candidate * candidate] = [candidate]
            else:
                for prime in sieve[candidate]:
                    sieve.setdefault(candidate + prime, []).append(prime)
                del sieve[candidate]
            candidate += 1
    if n < 2:
        return []
    result = []
    for prime in _primes():
        if prime > n:
            break
        result.append(prime)
    return result

